import{_ as a,o as t,c as o,a3 as s}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Data & Sync","description":"","frontmatter":{},"headers":[],"relativePath":"data-sync-security.md","filePath":"data-sync-security.md","lastUpdated":1784726145000}'),r={name:"data-sync-security.md"};function i(n,e,l,c,p,d){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="data-sync" tabindex="-1">Data &amp; Sync <a class="header-anchor" href="#data-sync" aria-label="Permalink to &quot;Data &amp; Sync&quot;">​</a></h1><p>This guide explains how Notely stores your data and how to keep work safe when collaborating.</p><h2 id="_1-where-notely-stores-app-data" tabindex="-1">1. Where Notely Stores App Data <a class="header-anchor" href="#_1-where-notely-stores-app-data" aria-label="Permalink to &quot;1. Where Notely Stores App Data&quot;">​</a></h2><p>Notely keeps your notes in your selected workspace folder.</p><p>It also creates a <code>.notes-app</code> folder for app-managed data such as:</p><ul><li>Note version history</li><li>Workspace settings</li><li>Image annotations</li></ul><p>You usually do not need to open or edit those files yourself.</p><h2 id="_2-keep-your-notes-safe" tabindex="-1">2. Keep Your Notes Safe <a class="header-anchor" href="#_2-keep-your-notes-safe" aria-label="Permalink to &quot;2. Keep Your Notes Safe&quot;">​</a></h2><p>Notely includes built-in safety features:</p><ul><li>Version history for restoring previous note content</li><li>Managed handling for removed notes/folders</li><li>Conflict tools when synced changes overlap</li></ul><p>Best practice: make sure your workspace folder is backed up regularly.</p><h2 id="_3-sync-with-other-peers-p2p" tabindex="-1">3. Sync with Other Peers (P2P) <a class="header-anchor" href="#_3-sync-with-other-peers-p2p" aria-label="Permalink to &quot;3. Sync with Other Peers (P2P)&quot;">​</a></h2><ol><li>Open <strong>P2P -&gt; P2P Status</strong>.</li><li>Start discovery.</li><li>Pair with a trusted peer using invite code.</li><li>Watch sync status and resolve conflicts if prompted.</li></ol><p>Tips:</p><ul><li>Pair only with trusted devices.</li><li>Rotate workspace keys when team access changes.</li></ul><p>If you do not share notes between devices, you can ignore this section.</p><h2 id="_4-ai-features-for-daily-use" tabindex="-1">4. AI Features for Daily Use <a class="header-anchor" href="#_4-ai-features-for-daily-use" aria-label="Permalink to &quot;4. AI Features for Daily Use&quot;">​</a></h2><ol><li>Open <strong>AI -&gt; AI Settings</strong>.</li><li>Add the sign-in details for the AI service you want to use.</li><li>Use AI chat, smarter search, and related-note features as needed.</li></ol><p>If the service you chose cannot do something, Notely shows a warning in AI Settings.</p><h2 id="_5-when-to-use-workspace-graph" tabindex="-1">5. When to Use Workspace Graph <a class="header-anchor" href="#_5-when-to-use-workspace-graph" aria-label="Permalink to &quot;5. When to Use Workspace Graph&quot;">​</a></h2><p>Open <strong>Workspace -&gt; Workspace Graph</strong> when you want to:</p><ul><li>Find related notes quickly</li><li>Spot disconnected notes</li><li>Understand media-to-note relationships</li></ul><h2 id="_6-before-sharing-or-releasing-notes" tabindex="-1">6. Before Sharing or Releasing Notes <a class="header-anchor" href="#_6-before-sharing-or-releasing-notes" aria-label="Permalink to &quot;6. Before Sharing or Releasing Notes&quot;">​</a></h2><p>Do this quick check:</p><ol><li>Validate markdown issues.</li><li>Review typo warnings.</li><li>Open important diagrams in preview.</li><li>Confirm linked files still open correctly.</li></ol>',25)])])}const y=a(r,[["render",i]]);export{u as __pageData,y as default};
